<?php
 namespace League\CommonMark; use League\CommonMark\Block\Element\AbstractBlock; class UnmatchedBlockCloser { private $context; private $oldTip; private $lastMatchedContainer; public function __construct(ContextInterface $context) { $this->context = $context; $this->resetTip(); } public function setLastMatchedContainer(AbstractBlock $block) { $this->lastMatchedContainer = $block; } public function closeUnmatchedBlocks() { $endLine = $this->context->getLineNumber() - 1; while ($this->oldTip !== $this->lastMatchedContainer) { $oldTip = $this->oldTip->parent(); $this->oldTip->finalize($this->context, $endLine); $this->oldTip = $oldTip; } } public function resetTip() { if ($this->context->getTip() === null) { throw new \RuntimeException('No tip to reset to'); } $this->oldTip = $this->context->getTip(); } public function areAllClosed(): bool { return $this->context->getTip() === $this->lastMatchedContainer; } } 